// Format stale ticket alert message
const staleTickets = $input.all();

if (staleTickets.length === 0) {
  return [{ json: { hasStale: false, message: '✅ No stale tickets in Sprint 1. All tickets updated within 48 hours.' } }];
}

const rows = staleTickets.map(item => {
  const t = item.json;
  const lastUpdate = new Date(t.updated_at);
  const daysSince = Math.floor((Date.now() - lastUpdate.getTime()) / (1000 * 60 * 60 * 24));
  return `• *${t.ticket_id}* — ${t.title} (${t.squad || 'Unassigned'}) — last updated *${daysSince}d ago*`;
}).join('\n');

return [{
  json: {
    hasStale: true,
    count: staleTickets.length,
    message: `🚨 *${staleTickets.length} Stale Ticket(s) in Sprint 1*\n\nTickets not updated in 2+ days:\n${rows}\n\n_Action: Update ticket status before today's stand-up or flag as blocked._`
  }
}];

// Format velocity report
const velocityRows = $input.all();

const rows = velocityRows.map(item => {
  const v = item.json;
  const pct = v.velocity_pct || 0;
  const bar = '▓'.repeat(Math.floor(pct / 10)) + '░'.repeat(10 - Math.floor(pct / 10));
  return `*${v.squad}*: ${bar} ${pct}% (${v.completed_points}/${v.planned_points}pts)`;
}).join('\n');

const totalPlanned = velocityRows.reduce((acc, i) => acc + (i.json.planned_points || 0), 0);
const totalDone = velocityRows.reduce((acc, i) => acc + (i.json.completed_points || 0), 0);
const overallPct = totalPlanned > 0 ? Math.round((totalDone / totalPlanned) * 100) : 0;

return [{
  json: {
    message: `📊 *Sprint 1 Velocity Report*\n\n${rows}\n\n*Overall: ${overallPct}% (${totalDone}/${totalPlanned} pts)*\n\n_Generated by n8n · ${new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long' })}_`
  }
}];

// Parse and validate incoming workshop findings
const body = $input.first().json.body || $input.first().json;

const required = ['user_group', 'pain_points', 'facilitator'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  return [{ json: { error: true, message: `Missing required fields: ${missing.join(', ')}` } }];
}

// Validate minimum pain points
const painPoints = Array.isArray(body.pain_points) ? body.pain_points : [body.pain_points];
if (painPoints.length < 3) {
  return [{ json: { error: true, message: `Minimum 3 pain points required. Got ${painPoints.length}.` } }];
}

const USER_GROUPS = ['customer','seller','delivery_driver','customer_support_agent','nutritionist','ui_ux_designer','software_engineer','legal_compliance','data_analyst','senior_partner','stakeholder'];

if (!USER_GROUPS.includes(body.user_group)) {
  return [{ json: { error: true, message: `Invalid user_group: ${body.user_group}` } }];
}

return [{ json: { error: false, validated: true, data: { ...body, pain_points: painPoints, received_at: new Date().toISOString() } } }];

const tickets = $input.all().map(i => i.json);

const doneTickets = tickets.filter(t => t.status === 'done');
const notDone = tickets.filter(t => t.status !== 'done');
const unsignedOff = doneTickets.filter(t => !t.pm_signed_off);

const summary = [
  `*Sprint 1 Pre-Review DoD Audit*`,
  ``,
  `📋 *Ticket Status*`,
  `• Done: ${doneTickets.length}/${tickets.length}`,
  `• Remaining: ${notDone.length}`,
  `• Awaiting PM sign-off: ${unsignedOff.length}`,
  ``,
  notDone.length > 0 ? `⚠️ *Incomplete Tickets*\n${notDone.map(t => `• ${t.ticket_id} — ${t.title} (${t.status})`).join('\n')}` : '✅ All tickets complete',
  ``,
  unsignedOff.length > 0 ? `🔏 *Needs PM Sign-off*\n${unsignedOff.map(t => `• ${t.ticket_id} — ${t.title}`).join('\n')}` : '✅ All done tickets signed off',
  ``,
  `_Sprint 1 Review scheduled for Day 12 · Retro Day 13_`
].join('\n');

return [{ json: { message: summary } }];
